parameters.jsCode:
// Normaliza o payload da Evolution API
// Eventos relevantes: 'messages.upsert'
// NAO ignora mais midia/sem texto: imagem, video, documento e figurinha viram
// placeholder; audio e marcado (is_audio) para transcricao posterior via Whisper.

const body = items[0].json.body || items[0].json;
const event = body.event;

if (event !== 'messages.upsert') {
  return [{ json: { skip: true, reason: 'evento_nao_relevante', event } }];
}

const data = body.data || {};
const key = data.key || {};
const remoteJid = key.remoteJid || '';
const fromMe = !!key.fromMe;
const msgId = key.id;

// Ignora grupos (terminam em @g.us)
if (remoteJid.endsWith('@g.us')) {
  return [{ json: { skip: true, reason: 'mensagem_de_grupo' } }];
}

const number = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');
if (!number) {
  return [{ json: { skip: true, reason: 'sem_numero' } }];
}

const msg = data.message || {};

// Reacoes e mensagens de protocolo nao sao conteudo de conversa
if (msg.reactionMessage || msg.protocolMessage || Object.keys(msg).length === 0) {
  return [{ json: { skip: true, reason: 'mensagem_sem_conteudo' } }];
}

// Texto direto (cobrindo varios formatos)
let content =
  msg.conversation ||
  (msg.extendedTextMessage && msg.extendedTextMessage.text) ||
  (msg.imageMessage && msg.imageMessage.caption) ||
  (msg.videoMessage && msg.videoMessage.caption) ||
  (msg.documentMessage && msg.documentMessage.caption) ||
  '';

let isAudio = false;
let mediaType = content ? 'texto' : null;

// Sem texto: marca o tipo de midia em vez de descartar a mensagem
if (!content) {
  if (msg.audioMessage) {
    isAudio = true; mediaType = 'audio';
    content = '[Audio recebido - transcrevendo...]';
  } else if (msg.imageMessage) {
    mediaType = 'imagem'; content = '[Imagem enviada pelo mentorado]';
  } else if (msg.videoMessage) {
    mediaType = 'video'; content = '[Video enviado pelo mentorado]';
  } else if (msg.documentMessage) {
    mediaType = 'documento'; content = '[Documento enviado pelo mentorado]';
  } else if (msg.stickerMessage) {
    mediaType = 'figurinha'; content = '[Figurinha enviada pelo mentorado]';
  } else {
    mediaType = 'outro'; content = '[Mensagem sem texto recebida]';
  }
}

const pushName = data.pushName || null;
const instancia = body.instance || body.instanceName || null;

return [{
  json: {
    skip: false,
    direction: fromMe ? 'outgoing' : 'incoming',
    whatsapp_number: number,
    contact_name: pushName,
    content,
    media_type: mediaType,
    is_audio: isAudio,
    message_key: { remoteJid, fromMe, id: msgId },
    evolution_msg_id: msgId,
    instancia,
    raw_event: event
  }
}];

// ============================================================
// CONFIGURAÇÃO DO SUPABASE
// Chave SECRETA (service_role / sb_secret_...) — permite ao n8n salvar
// as sugestoes mesmo com a trava (RLS) ligada. Vai SO no n8n, nunca no painel.
// ============================================================
return [{
  json: {
    supabase_url: 'https://lpuhixhuenpwuawqtcmv.supabase.co',
    supabase_anon_key: 'COLE_AQUI_SUA_SECRET_KEY'
  }
}];

// Guard: se a API falhou ou veio resposta vazia, descarta o item
// (evita inserir linha vazia em sugestoes no painel)
if ($json._api_error || $json.error || !$json.content || !Array.isArray($json.content) || $json.content.length === 0) {
  return null;
}

// Parse da resposta do Redator + monta o objeto final
const redatorResp = $json;
const original = $('Montar Request: Redator').item.json;

const rawText = (redatorResp.content?.[0]?.text || '').trim();

const respostaMatch = rawText.match(/RESPOSTA_FINAL:\s*([\s\S]+?)(?=\n\nNOTA_PARA_O_CS:|$)/);
const notaMatch     = rawText.match(/NOTA_PARA_O_CS:\s*([\s\S]+?)$/);

const sugestaoResposta = respostaMatch ? respostaMatch[1].trim() : rawText;
const lembrete = notaMatch ? notaMatch[1].trim().replace(/^nenhuma$/i, '') : '';

return {
  json: {
    whatsapp_number: original.whatsapp_number,
    contact_name: original.contact_name || 'Sem nome',
    qtd_mensagens: Number(original.qtd_mensagens),
    horas_aguardando: original.horas_aguardando,
    mensagens: original.mensagens_concatenadas,
    urgencia: (original.urgencia || 'MEDIA').toUpperCase(),
    intencao: (original.categoria || 'NAO_MAPEADA').toUpperCase(),
    justificativa: original.motivo || '',
    sugestao_resposta: sugestaoResposta,
    lembrete
  }
};

// ============================================================
// CONFIGURAÇÃO DO SUPABASE
// Chave SECRETA (service_role / sb_secret_...) — permite ao n8n salvar
// as sugestoes mesmo com a trava (RLS) ligada. Vai SO no n8n, nunca no painel.
// ============================================================
return [{
  json: {
    supabase_url: 'https://lpuhixhuenpwuawqtcmv.supabase.co',
    supabase_anon_key: 'COLE_AQUI_SUA_SECRET_KEY'
  }
}];

// Pula conversas que já têm uma sugestão PENDENTE no painel,
// pra não reenviar pra IA e economizar API.
const conversas = $('Buscar Conversas Nao Lidas').all();
const pendentes = $('Buscar Sugestoes Pendentes').all();

const jaPendentes = new Set();
for (const item of pendentes) {
  const j = item.json;
  if (Array.isArray(j)) {
    j.forEach(x => { if (x && x.whatsapp_number) jaPendentes.add(String(x.whatsapp_number)); });
  } else if (j && j.whatsapp_number) {
    jaPendentes.add(String(j.whatsapp_number));
  }
}

// Mantém só quem ainda NÃO tem sugestão pendente
const novas = conversas.filter(c => !jaPendentes.has(String(c.json.whatsapp_number)));
return novas;

// ============================================================
// CONFIG DA TRANSCRICAO DE AUDIO
// Preencha a URL base e a apikey da SUA instancia Evolution para baixar o audio,
// e o endpoint/modelo de transcricao (padrao OpenAI Whisper).
//
// Para usar a Groq (mais barata, modelo v3) troque so estes dois campos:
//   transcribe_url: 'https://api.groq.com/openai/v1/audio/transcriptions'
//   transcribe_model: 'whisper-large-v3'
// (a Groq e compativel com a API da OpenAI, o resto do fluxo nao muda)
// ============================================================
return {
  json: {
    ...$json,
    evolution_url: 'https://COLE_AQUI_SUA_URL_EVOLUTION',
    evolution_apikey: 'COLE_AQUI_SUA_APIKEY_EVOLUTION',
    transcribe_url: 'https://api.openai.com/v1/audio/transcriptions',
    transcribe_model: 'whisper-1'
  }
};

// Usa a transcricao do Whisper como conteudo da mensagem.
// Se a transcricao falhar, mantem um placeholder e nao quebra a ingestao.
const orig = $('Normalizar Payload').item.json;
const texto = ($json.text || '').trim();
const content = texto
  ? texto
  : '[Audio recebido - nao foi possivel transcrever automaticamente]';
return {
  json: {
    whatsapp_number: orig.whatsapp_number,
    contact_name: orig.contact_name,
    content,
    media_type: 'audio',
    evolution_msg_id: orig.evolution_msg_id,
    instancia: orig.instancia,
    direction: 'incoming'
  }
};

// Ponto de juncao das duas ramificacoes (audio transcrito ou mensagem comum).
// Normaliza os campos que o Upsert/Insert vao usar.
const j = $json;
return {
  json: {
    whatsapp_number: j.whatsapp_number,
    contact_name: j.contact_name || null,
    content: j.content,
    evolution_msg_id: j.evolution_msg_id,
    instancia: j.instancia || null
  }
};

parameters.query:
INSERT INTO messages (contact_id, whatsapp_number, contact_name, direction, content, evolution_msg_id, status, instancia)
VALUES (upsert_contact($1, $2), $1, $2, 'outgoing', $3, $4, 'read', $5)
ON CONFLICT (evolution_msg_id) DO NOTHING;
